  search: function(keyword) {
    let results = [];
    if (!keyword) return results;
    keyword = keyword.toLowerCase();
    let self = this;
    Object.keys(self.content).forEach(function(num) {
      let lesson = self.content[num];
      let text = (lesson.title + ' ' + lesson.text).toLowerCase();
      if (text.indexOf(keyword) >= 0) {
        results.push({lesson: parseInt(num), title: lesson.title, relevance: 'high'});
      }
    });
    Object.keys(self.quickRef).forEach(function(key) {
      let val = self.quickRef[key];
      if ((key + ' ' + val).toLowerCase().indexOf(keyword) >= 0) {
        results.push({quickRef: key, value: val, relevance: 'medium'});
      }
    });
    Object.keys(self.mixun).forEach(function(num) {
      let m = self.mixun[num];
      if ((m.file + ' ' + m.text).toLowerCase().indexOf(keyword) >= 0) {
        results.push({mixun: parseInt(num), file: m.file, relevance: 'low'});
      }
    });
    return results;
  },

  getLesson: function(num) {
    return this.content[num] || null;
  },

  getTitle: function(num) {
    return this.lessons[num] || '';
  },

  getContext: function(keyword, maxLen) {
    maxLen = maxLen || 200;
    keyword = (keyword || '').toLowerCase();
    let contexts = [];
    let self = this;
    Object.keys(self.content).forEach(function(num) {
      let lesson = self.content[num];
      let text = lesson.text;
      let idx = text.toLowerCase().indexOf(keyword);
      while (idx >= 0 && contexts.length < 10) {
        let start = Math.max(0, idx - maxLen/2);
        let end = Math.min(text.length, idx + keyword.length + maxLen/2);
        contexts.push({
          lesson: parseInt(num),
          title: lesson.title,
          snippet: text.substring(start, end)
        });
        idx = text.toLowerCase().indexOf(keyword, idx + keyword.length);
      }
    });
    return contexts;
  }
